module RefModule(
    input               clk,
    input               rst,
    input               load,
    input [7:0]         parallel_in,
    input               serial_in,

    output reg [7:0]    data_out
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge rst or posedge dbg_halt) begin
    if (rst)
        data_out <= 8'b00000000;
    else if (load)
        data_out <= parallel_in;
    else
        data_out <= {data_out[6:0], serial_in};
end

endmodule
